{"code": "import json
import re

# Load all data files
files = {
    'packages': locals()['var_functions.query_db:30'],
    'project_pvs': locals()['var_functions.query_db:52'],
    'project_infos': locals()['var_functions.query_db:28']
}

data = {}
for key, file_path in files.items():
    with open(file_path, 'r') as f:
        data[key] = json.load(f)

packages = data['packages']
project_pvs = data['project_pvs']
project_infos = data['project_infos']

# Step 1: Parse packages and find latest releases
print('Parsing packages...')
for pkg in packages:
    version_info = pkg['VersionInfo']
    is_release = '"IsRelease": true' in version_info
    ordinal = 0
    match = re.search(r'"Ordinal":\s*(\d+)', version_info)
    if match:
        ordinal = int(match.group(1))
    pkg['IsRelease'] = is_release
    pkg['Ordinal'] = ordinal

# Filter latest releases
release_packages = [pkg for pkg in packages if pkg['IsRelease']]
latest_by_package = {}
for pkg in release_packages:
    name = pkg['Name']
    if name not in latest_by_package or pkg['Ordinal'] > latest_by_package[name]['Ordinal']:
        latest_by_package[name] = {
            'Name': name,
            'Version': pkg['Version'],
            'Ordinal': pkg['Ordinal']
        }

latest_packages = list(latest_by_package.values())
print(f'Found {len(latest_packages)} latest package releases')

# Step 2: Create mapping from project_pvs
print('Creating package to project mapping...')
package_to_project = {}
for pv in project_pvs:
    key = (pv['Name'], pv['Version'])
    package_to_project[key] = pv['ProjectName']

print(f'Created mapping for {len(package_to_project)} package versions')

# Step 3: Extract stars from project_infos
print('Extracting GitHub stars...')
project_to_stars = {}
for info in project_infos:
    proj_info = info.get('Project_Information', '')
    # Extract stars count using regex
    match = re.search(r'(\d+(?:,\d+)*)\s+stars?', proj_info)
    if match:
        stars_str = match.group(1).replace(',', '')
        try:
            stars = int(stars_str)
            # Extract project name from the text
            proj_match = re.search(r'project\s+([^\s]+/[^\s\)]+)', proj_info)
            if proj_match:
                proj_name = proj_match.group(1)
                project_to_stars[proj_name] = stars
        except:
            pass

print(f'Extracted stars for {len(project_to_stars)} projects')
print('Sample projects with stars:')
for i, (proj, stars) in enumerate(list(project_to_stars.items())[:5]):
    print(f'  {proj}: {stars} stars')

# Step 4: Match packages with stars
print('Matching packages with stars...')
package_stars = []
matched_count = 0
for pkg in latest_packages:
    key = (pkg['Name'], pkg['Version'])
    if key in package_to_project:
        project_name = package_to_project[key]
        if project_name in project_to_stars:
            stars = project_to_stars[project_name]
            package_stars.append({
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Project': project_name,
                'Stars': stars
            })
            matched_count += 1

print(f'Matched {matched_count} packages with stars')

